import React from 'react';
import { Link } from 'react-router-dom';

import pageCSS from './page.module.css';
import css from './landing.module.css';

import Header from '../components/Header';

export default function Landing() {
	return (
		<div className={pageCSS.pageContainer}>
			<Header />
			<div className={css.container}>
				<h3 className={css.greeting}>Hello, I'm</h3>
				<h1 className={css.name}>Gabriel Figueiredo</h1>
				<p className={css.resume}>
					Lorem ipsum dolor sit amet, consectetur adipiscing elit. Quisque eu ipsum ut urna condimentum accumsan a
					auctor nulla. Donec bibendum dolor dui, a mollis dui sodales in. Orci varius natoque penatibus et magnis dis
					parturient montes, nascetur ridiculus mus.
				</p>
				<Link className={css.button} to="/projects">
					Check out some of my projects
				</Link>
			</div>
		</div>
	);
}
